mapper.sql:
FROM ai_chat_log l
LEFT JOIN sys_user u ON l.user_id = u.id AND u.deleted = 0
LEFT JOIN knowledge_base k ON l.knowledge_id = k.id
WHERE 1 = 1

    AND u.username LIKE CONCAT('%', #{username}, '%')


    AND u.user_type = #{userType}


    AND k.category = #{kbCategory}


    AND (


            (l.knowledge_id IS NOT NULL AND (l.confidence IS NULL OR l.confidence >= 0.3))


            (l.knowledge_id IS NULL)


            (l.confidence IS NOT NULL AND l.confidence < 0.3)

        1=1

    )


    AND l.create_time >= #{startTime}


    AND l.create_time <= #{endTime}
